+    #[test]
+    fn gallery_render_deterministic_with_overrides() {
+        let keys = [
+            KeyCode::Char('v'),
+            KeyCode::Char('h'),
+            KeyCode::Char('z'),
+            KeyCode::Char('b'),
+            KeyCode::Char('l'),
